187→const hasSupportedMediaExtension = (fileName = '') => {
188→    const lowerFileName = fileName.toLowerCase();
189→    return PROFILE_MEDIA_EXTENSIONS.some((ext) => lowerFileName.endsWith(ext));
190→};
