            <div
                className="rp-card-accent"
                style={{ opacity: accentOpacity }}
            />
            <div className="rp-card-content">
                <h4 className="rp-card-title">{title}</h4>
                {excerpt && <p className="rp-card-excerpt">{excerpt}</p>}
                <div className="rp-card-meta">
