import { useEffect, useRef, useState } from "react";
import { MoonLoader } from "react-spinners";
import { useQuery } from "@tanstack/react-query";
import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import { getMonthlyHottestJournals, getInterestSections, searchJournals, searchUsers } from "../../../../API/Api";
import { useAuth } from "../../../Context/useAuth";
import { handleClickProfile } from "../../../../helpers/handleClicks";
import ParseContent from "../postCards/parseData";
import CalculateText from "../postCards/calculateReadingTime";
import formatPostDate from "../../../../helpers/formatDateString";
import VerifiedBadge from "../../Badge/VerifiedBadge";
import { handleImageFallback } from "../../../utils/handleImageFallback";
import { useAddViewsMutation } from "../../../utils/useMutation";
import UserSearchResults from "./UserSearchResults";
import InterestSections from "./InterestSections";
import "../postCards/postcards.css";
import "./explore.css";
import "./userSearch.css";

const getHotScore = (journal) => {
    if(typeof journal?.hot_score === "number"){
        return journal.hot_score;
    }

    const likes = journal?.like_count?.[0]?.count || 0;
    const comments = journal?.comment_count?.[0]?.count || 0;
    const bookmarks = journal?.bookmark_count?.[0]?.count || 0;
    const views = journal?.views || 0;

    return (views * 6) + (likes * 3) + (comments * 2) + (bookmarks * 2);
};

const FlameIcon = ({ className }) => (
    <svg className={className} viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
        <path d="M12 2C10.97 6.5 6 9.5 6 14C6 17.31 8.69 20 12 20C15.31 20 18 17.31 18 14C18 9.5 13.03 6.5 12 2Z" fill="currentColor"/>
        <path d="M12 20C10.34 20 9 18.66 9 17C9 15 12 12 12 12C12 12 15 15 15 17C15 18.66 13.66 20 12 20Z" fill="var(--bg-card)" opacity="0.6"/>
    </svg>
);

const HeroCard = ({ journal, hotScore, onClick }) => {
    const thumbnail = journal?.thumbnail_url || null;
    const previewText = journal?.preview_text || '';
    return (
    <motion.div
        className="explore-hero-wrap"
        initial={{ opacity: 0, y: 20 }}
