        className="explore-hero-wrap"
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
    >
        <div className="explore-hero-glow" />
        <div
            className="explore-hero-card"
            onClick={() => onClick(journal.id)}
            role="button"
            tabIndex={0}
            onKeyDown={(e) => {
                if(e.key === "Enter" || e.key === " "){
                    e.preventDefault();
                    onClick(journal.id);
                }
            }}
        >

        {thumbnail && (
            <div className="explore-hero-image-wrap">
                <img
                    className="explore-hero-image"
                    src={thumbnail}
                    alt={journal?.title ? `${journal.title} cover image` : "Post cover image"}
                    loading="eager"
                    onError={handleImageFallback}
                />
                <div className="explore-hero-image-overlay" />
            </div>
        )}

        <div className={`explore-hero-body ${thumbnail ? "explore-hero-body--has-image" : ""}`}>
            <div className="explore-hero-badge">
                <FlameIcon className="explore-hero-flame" />
                <span className="explore-hero-badge-text">#1 Hottest</span>
            </div>

            <h2 className="explore-hero-title">
                {journal?.title?.length > 80 ? `${journal.title.substring(0, 80)}...` : (journal?.title || "Untitled")}
            </h2>

            <p className="explore-hero-excerpt">{previewText}</p>

            <div className="explore-hero-footer">
                <div className="explore-hero-author">
                    <div className={`user-avatar-container ${journal?.users?.badge === "legend" ? "avatar-ring-legend" : journal?.users?.badge === "og" ? "avatar-ring-og" : ""}`}>
                        <img
                            loading="lazy"
                            className="user-info-avatar"
                            src={journal?.users?.image_url || "/assets/profile.jpg"}
                            alt={`${journal?.users?.name || "User"} profile picture`}
                        />
                    </div>
                    <div className="user-name-container">
                        <p className="user-newsfeed-name">{journal?.users?.name || "Unknown author"}</p>
                        <VerifiedBadge badge={journal?.users?.badge} size={14} />
                    </div>
                    <div className="name-info-separator">•</div>
                    <p className="user-post-date">{formatPostDate(journal?.created_at)}</p>
                </div>

                <div className="explore-hero-stats">
                    <div className="explore-hero-score-pill">
                        <FlameIcon className="explore-hero-score-flame" />
                        {hotScore}
                    </div>
                    <div className="reading-time-container">
                        <p className="reading-time-text">{CalculateText(previewText)}</p>
                    </div>
                </div>
            </div>
        </div>
        </div>
    </motion.div>
    );
};

const RunnerCard = ({ journal, index, hotScore, onClick }) => {
    const thumbnail = journal?.thumbnail_url || null;
    const previewText = journal?.preview_text || '';
    return (
    <motion.div
        className="explore-runner-card"
        onClick={() => onClick(journal.id)}
        role="button"
        tabIndex={0}
        onKeyDown={(e) => {
            if(e.key === "Enter" || e.key === " "){
                e.preventDefault();
                onClick(journal.id);
            }
        }}
        initial={{ opacity: 0, y: 14 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4, delay: 0.08 * index, ease: [0.22, 1, 0.36, 1] }}
    >
        <div className="explore-runner-rank-col">
            <span className={`explore-runner-rank ${index <= 2 ? "explore-runner-rank--top" : ""}`}>
                {index + 1}
            </span>
        </div>

        <div className="explore-runner-body">
            <h3 className="explore-runner-title">
                {journal?.title?.length > 60 ? `${journal.title.substring(0, 60)}...` : (journal?.title || "Untitled")}
            </h3>
            <p className="explore-runner-excerpt">{previewText}</p>
            <div className="explore-runner-meta">
                <div className="explore-runner-author">
                    <div className={`user-avatar-container ${journal?.users?.badge === "legend" ? "avatar-ring-legend" : journal?.users?.badge === "og" ? "avatar-ring-og" : ""}`}>
                        <img
                            loading="lazy"
                            className="user-info-avatar"
                            src={journal?.users?.image_url || "/assets/profile.jpg"}
                            alt={`${journal?.users?.name || "User"} profile picture`}
                        />
                    </div>
                    <p className="user-newsfeed-name">{journal?.users?.name || "Unknown author"}</p>
                    <VerifiedBadge badge={journal?.users?.badge} size={12} />
                    <div className="name-info-separator">•</div>
                    <p className="user-post-date">{formatPostDate(journal?.created_at)}</p>
                </div>
                <div className="explore-runner-stats">
                    <div className="explore-score-pill">
                        <FlameIcon className="explore-runner-flame-icon" />
                        {hotScore}
                    </div>
