const parseLimitWithinRange = (value, min, max, fallback = null) => {
    const parsed = Number.parseInt(value, 10);
    if (Number.isNaN(parsed)) {
        return fallback;
    }
    if (parsed < min || parsed > max) {
        return null;
    }
    return parsed;
};

const BUCKET_RESIZE_LIMITS = {
    avatars:        { width: 400,  height: 400,  fit: 'cover' },
    background:     { width: 1920, height: 1080, fit: 'inside' },
    'story-covers': { width: 800,  height: 1200, fit: 'inside' },
    'journal-images': { width: 1600, height: 1600, fit: 'inside' },
};

export const imageUploader = async(file, userId, bucket) =>{
    if(!file){
        throw new Error('no file received');
    }

    const sourceBuffer = Buffer.isBuffer(file) ? file : file?.buffer;
    if(!sourceBuffer){
        throw new Error('invalid file payload');
    }

    let img_buffer = null
    let img_url = null
    let pipeline = sharp(sourceBuffer);
    const limits = BUCKET_RESIZE_LIMITS[bucket];
    if(limits){
        pipeline = pipeline.resize(limits.width, limits.height, { fit: limits.fit, withoutEnlargement: true });
    }
    img_buffer = await pipeline
    .webp({quality: 80})
    .toBuffer();

    const folderName = `user_id_${userId}`;
    const fileName = `${Date.now()}_${crypto.randomUUID()}.webp`;
    const filePath = `${folderName}/${fileName}`;

    const {data: uploadImage, error: errorUploadImage} = await supabase.storage
    .from(bucket)
    .upload(filePath, img_buffer, {
        contentType: 'image/webp',
        cacheControl: '31536000',
        upsert: true
    })
    if(errorUploadImage){
        console.error('supabase error while uploading image to supabase bucket', errorUploadImage)
        throw new Error('error uploading image into supabase bucket');
    }
    const {data: data_url} = supabase.storage
    .from(bucket)
    .getPublicUrl(filePath)

    if(data_url){
        img_url = data_url.publicUrl;
        return img_url;
    } else {
        throw new Error('Error uploading the image');
    }
}

