                                            <p>{journal.journals.title}</p>
                                        </motion.div>
                                    )}
                                </div>
                            </div>
                        </div>

                    </motion.div>
                )
            })}
            <div ref={inviewRef} className='inview-container'>
                <MoonLoader loading={isFetchingNextPage} color="rgba(255, 255, 255, 0.64)" speedMultiplier={1} size={20}/>
            </div>
        </div>
        </>
    )
}
export default Bookmarks;

