    const handleclickUserProfile = handleClickProfile(navigate);

    const handleClickBookmarkSettings = (e, journalId) => {
        e.stopPropagation();
        setBookmarkIdSettings(journalId === bookmarkIdSettings ? null : journalId)
    }

