249→                            </div>
250→                        </div>
251→
252→                    </motion.div>
253→                )
254→            })}
255→            <div ref={inviewRef} className='inview-container'>
256→                <MoonLoader loading={isFetchingNextPage} color="rgba(255, 255, 255, 0.64)" speedMultiplier={1} size={20}/>
257→            </div>
258→        </div>
259→        </>
260→    )
261→}
