                                                            {setting.icon}
                                                            {setting.label}
                                                        </div>
                                                    )}
                                                </div>
                                            ))}
                                        </motion.div>
                                    </AnimatePresence>
                                )}
                            </motion.div>
                        );
                    })}
                </div>
            ) : (
            <div className="postcards-list-view">
            {journals.map((journal, index) => {
                const previewText = journal?.preview_text || '';
                const thumbnail = journal?.thumbnail_url || null;
                return (
                    <motion.div
                        key={journal.id}
                        className='profile-postcards-child-container'
                        initial={{opacity: 0, y: 12}}
                        animate={{opacity: 1, y: 0}}
                        transition={{duration: 0.3, ease: 'easeOut'}}
                    >

                        <div className="profile-postcards">

                            {showConfirmationBttn === journal.id && (
                                <AnimatePresence>
                                <div className="confirmation-delete-bg">

